BOUNDARY VALUE ANALYSIS
INPUT: min_value, max_value
OUTPUT: Test values

BEGIN
 test_values = []

 // Add values just below boundary
 test_values.add(min_value - 1)

 // Add boundary values
 test_values.add(min_value)
 test_values.add(max_value)

 // Add values just above boundary
 test_values.add(max_value + 1)

 // Add typical valid value
 test_values.add((min_value + max_value) / 2)

 RETURN test_values
END

// Example: For age 1-100
// Output: 0, 1, 100, 101, 50

EQUIVALENCE PARTITIONING
INPUT: input_range
OUTPUT: Partitions

BEGIN
 partitions = []

 // Valid partition
 valid_partition = {
 min: input_range.valid_min,
 max: input_range.valid_max,
 type: "VALID"
 }

 // Invalid partitions
 invalid_below = {
 value: input_range.valid_min - 1,
 type: "INVALID_BELOW"
 }

 invalid_above = {
 value: input_range.valid_max + 1,
 type: "INVALID_ABOVE"
 }

 partitions.add(valid_partition)
 partitions.add(invalid_below)
 partitions.add(invalid_above)

 RETURN partitions
END

// Example: Age input (1-100)
// Partitions: 1-100 (valid), <1 (invalid), >100 (invalid)
